SELECT id, reservation_id, device_id, user_id, borrow_time, return_time, expected_return_time, status,
       borrow_check_status, return_check_status, remark, operator_id, return_operator_id, created_at, updated_at
FROM borrow_record
WHERE 1 = 1

      AND status = #{status}


      AND user_id = #{userId}

ORDER BY borrow_time DESC, created_at DESC
LIMIT #{limit} OFFSET #{offset}

SELECT COUNT(*)
FROM borrow_record
WHERE 1 = 1

      AND status = #{status}


      AND user_id = #{userId}
